// Core optimization loop
func Optimize(n Node) Node {
// 1. Recursive Constant Folding
n = ConstantFolder(n)

pre.code:
// 2. Boolean Logic Reduction
n = BooleanReducer(n)

// 3. Subtree Pruning Logic
if f, ok := n.(*LogicalFilter); ok {
    if lit, ok := f.Predicate.(*Literal); ok {
        if lit.Value == false {
            // Eliminate unreachable data path
            return &EmptyRelation{Schema: f.Schema()}
        }
    }
}
return n
